ae@ : 
I'm able to reproduce using "xorp" from ports and the following configuration file on a test hosts, which basically should disable MLDv2:

# cat /usr/local/etc/xorp.conf
interfaces {
    interface re0 {
        vif re0 {
            address 10.10.10.10 {
                prefix-length: 24
            }
            address fc00::1 {
                prefix-length: 64
            }
        }
    }                                             
}

protocols {
   mld {
     disable: false
     interface re0 {
        vif re0 {
          disable: false
          version: 1
        }
     }
   }
}
